597				auto loopDim = stmt.loopDims[i];
598				if (loopDim.loopVar && loopDim.range) {
599					loopVarStack[loopVarStack.size() - i - 1] = loopDim.range->left;
600					set_iterator_value(*loopDim.loopVar, loopDim.range->left);
601				}
602			}
603	
604			std::vector<slang::ast::ForeachLoopStatement::LoopDim> reversedDims(
605					stmt.loopDims.rbegin(), stmt.loopDims.rend());
